#!/usr/bin/env node

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import fs from "fs";
import path from "path";

const API_KEY = process.env.DEEPSEEK_API_KEY;
if (!API_KEY) {
  console.error("ERROR: DEEPSEEK_API_KEY required");
  process.exit(1);
}

const server = new Server(
  { name: "vision-reader", version: "1.0.0" },
  { capabilities: { tools: {} } }
);

function getMimeType(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  const map = {
    ".png": "image/png",
    ".jpg": "image/jpeg",
    ".jpeg": "image/jpeg",
    ".webp": "image/webp",
    ".gif": "image/gif",
    ".bmp": "image/bmp",
  };
  return map[ext] || "image/png";
}

async function describeImage(filePath, prompt) {
  if (!fs.existsSync(filePath)) {
    throw new Error(`File not found: ${filePath}`);
  }

  const mime = getMimeType(filePath);
  const imgBuffer = fs.readFileSync(filePath);
  const base64 = imgBuffer.toString("base64");
  const dataUri = `data:${mime};base64,${base64}`;

  const body = {
    model: "deepseek-v4-pro",
    messages: [
      {
        role: "user",
        content: [
          { type: "text", text: prompt || "请详细描述这张图片的内容。如果是截图或系统信息界面，请逐条列出所有可见的配置参数和数值。" },
          { type: "image_url", image_url: { url: dataUri } },
        ],
      },
    ],
    max_tokens: 4096,
  };

  const res = await fetch("https://api.deepseek.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${API_KEY}`,
    },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`DeepSeek API error ${res.status}: ${text}`);
  }

  const data = await res.json();
  return data.choices?.[0]?.message?.content || JSON.stringify(data);
}

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "describe_image",
      description:
        "读取并描述图片内容。支持 PNG/JPG/Webp/GIF/BMP。可用于识别截图中的文字、系统配置信息、UI 界面等。",
      inputSchema: {
        type: "object",
        properties: {
          file_path: {
            type: "string",
            description: "图片文件的绝对路径",
          },
          prompt: {
            type: "string",
            description: "可选，对图片提问或指定关注点。默认：详细描述图片内容，逐条列出配置参数",
          },
        },
        required: ["file_path"],
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name !== "describe_image") {
    throw new Error(`Unknown tool: ${request.params.name}`);
  }

  const { file_path, prompt } = request.params.arguments;
  const result = await describeImage(file_path, prompt);

  return {
    content: [{ type: "text", text: result }],
  };
});

process.on("SIGINT", async () => {
  await server.close();
  process.exit(0);
});

const transport = new StdioServerTransport();
await server.connect(transport);

